#!/usr/bin/env node
/**
 * regenerate-release-workbooks
 * ----------------------------
 * Clean regenerate flow for the v1.3 release workbook artifacts.
 *
 * 1. Delete only the well-known generated files inside docs/artifacts/.
 * 2. Preserve docs/artifacts/README.md and any unrelated files.
 * 3. Re-run `bun run docs:generate-release-workbook-templates`.
 * 4. Validate the manifest SHA256 hashes against the regenerated bytes.
 *
 * Safety:
 * - Refuses to delete any path outside <repo>/docs/artifacts/.
 * - Pure local filesystem ops + a single child process. No network.
 *
 * Exit codes:
 *   0 — regenerate + hash validation passed
 *   1 — any failure
 */
import {
  existsSync,
  mkdirSync,
  readFileSync,
  rmSync,
  statSync,
} from "node:fs";
import { dirname, join, resolve, relative, sep } from "node:path";
import { createHash } from "node:crypto";
import { spawnSync } from "node:child_process";
import process from "node:process";

const ROOT = process.cwd();
const ARTIFACT_DIR = join(ROOT, "docs", "artifacts");

export const GENERATED_FILENAMES = [
  "seed-production-tracking-v1.3-template.xlsx",
  "seed-production-tracking-v1.3-template.csv",
  "commercial-release-review-traceability-v1.3-template.xlsx",
  "commercial-release-review-traceability-v1.3-template.csv",
  "release-workbook-formula-contracts.md",
  "release-workbook-template-manifest.json",
];

export const PRESERVED_FILENAMES = ["README.md"];

/**
 * Returns true if `target` is a real, normal file strictly inside
 * `dir`. Defends against `..`, absolute paths, and symlinks pointing
 * outside the artifact dir.
 */
export function isSafeArtifactPath(target, dir) {
  const resolvedDir = resolve(dir);
  const resolvedTarget = resolve(target);
  const rel = relative(resolvedDir, resolvedTarget);
  if (!rel || rel.startsWith("..") || rel.includes(`..${sep}`)) return false;
  if (resolve(resolvedDir, rel) !== resolvedTarget) return false;
  return true;
}

function sha256OfFile(p) {
  return createHash("sha256").update(readFileSync(p)).digest("hex");
}

function deleteGeneratedFiles() {
  const deleted = [];
  for (const name of GENERATED_FILENAMES) {
    if (PRESERVED_FILENAMES.includes(name)) {
      throw new Error(`refusing to delete preserved file: ${name}`);
    }
    const target = join(ARTIFACT_DIR, name);
    if (!isSafeArtifactPath(target, ARTIFACT_DIR)) {
      throw new Error(`refusing unsafe delete path: ${target}`);
    }
    if (existsSync(target)) {
      const st = statSync(target);
      if (!st.isFile()) {
        throw new Error(`refusing to delete non-file: ${target}`);
      }
      rmSync(target, { force: true });
      deleted.push(relative(ROOT, target).replace(/\\/g, "/"));
    }
  }
  return deleted;
}

function runGenerator() {
  const r = spawnSync("bun", ["run", "docs:generate-release-workbook-templates"], {
    stdio: "inherit",
    env: process.env,
  });
  return r.status === 0 && !r.error;
}

function validateManifestHashes() {
  const manifestPath = join(ARTIFACT_DIR, "release-workbook-template-manifest.json");
  if (!existsSync(manifestPath)) {
    return { ok: false, mismatches: [{ filename: "manifest", reason: "missing" }] };
  }
  const manifest = JSON.parse(readFileSync(manifestPath, "utf8"));
  const mismatches = [];
  for (const f of manifest.files ?? []) {
    const abs = join(ROOT, f.path);
    if (!existsSync(abs)) {
      mismatches.push({ filename: f.filename, reason: "missing on disk" });
      continue;
    }
    const actual = sha256OfFile(abs);
    if (actual !== f.sha256) {
      mismatches.push({
        filename: f.filename,
        reason: "hash mismatch",
        expected: f.sha256,
        actual,
      });
    }
  }
  return { ok: mismatches.length === 0, mismatches, manifest };
}

function main() {
  if (!existsSync(ARTIFACT_DIR)) {
    mkdirSync(ARTIFACT_DIR, { recursive: true });
  }

  let deleted;
  try {
    deleted = deleteGeneratedFiles();
  } catch (err) {
    console.error(`Release Workbook Regenerate: FAIL\n  ${err.message}`);
    process.exit(1);
  }

  // Make sure the dir still exists after deletion (it may have been empty).
  if (!existsSync(ARTIFACT_DIR)) mkdirSync(ARTIFACT_DIR, { recursive: true });

  const genOk = runGenerator();
  if (!genOk) {
    console.error("\nRelease Workbook Regenerate: FAIL\n  generator step failed.");
    process.exit(1);
  }

  const { ok, mismatches, manifest } = validateManifestHashes();

  const regenerated = GENERATED_FILENAMES.filter((n) =>
    existsSync(join(ARTIFACT_DIR, n)),
  ).map((n) => `docs/artifacts/${n}`);

  console.log("");
  console.log(`Release Workbook Regenerate: ${ok ? "PASS" : "FAIL"}`);
  console.log("");
  console.log("Deleted generated artifacts:");
  if (deleted.length === 0) console.log("  (none — nothing to delete)");
  else for (const d of deleted) console.log(`  - ${d}`);
  console.log("");
  console.log("Regenerated:");
  for (const r of regenerated) console.log(`  - ${r}`);
  console.log("");
  if (manifest?.files) {
    console.log("SHA256 (from manifest):");
    for (const f of manifest.files) {
      console.log(`  ${f.sha256}  ${f.filename}`);
    }
    console.log("");
  }
  console.log(`Hash validation: ${ok ? "PASS" : "FAIL"}`);

  if (!ok) {
    console.error("");
    console.error("Hash validation failures:");
    for (const m of mismatches) {
      if (m.reason === "hash mismatch") {
        console.error(
          `  ${m.filename}\n    expected: ${m.expected}\n    actual:   ${m.actual}`,
        );
      } else {
        console.error(`  ${m.filename}: ${m.reason}`);
      }
    }
    console.error("");
    console.error("Run `bun run docs:verify-release-workbooks:diff` for focused diagnostics.");
    process.exit(1);
  }
}

const invokedDirectly =
  import.meta.url === `file://${process.argv[1]}` ||
  process.argv[1]?.endsWith("regenerate-release-workbooks.mjs");
if (invokedDirectly) main();
